command:
bash -lc 'REPO_ROOT=${PROJECT_DIR:-$(pwd)}; cd "$REPO_ROOT"; bash agent-eval/scripts/prepare-fast-gate.sh >/dev/null; TMP_ROOT=$(mktemp -d); trap "rm -rf $TMP_ROOT" EXIT; PORT=$(node -e '"'"'const net=require("node:net"); const s=net.createServer(); s.listen(0,"127.0.0.1",()=>{console.log(s.address().port); s.close();});'"'"'); mkdir -p "$TMP_ROOT/home"; cat > "$TMP_ROOT/.orca.json" <<EOF
{
  "providers": {
    "local": {
      "apiKey": "test-local-key",
      "baseURL": "http://127.0.0.1:$PORT/v1",
      "defaultModel": "qwen3:32b"
    }
  },
  "defaultProvider": "local"
}
EOF
(cd "$TMP_ROOT" && env -i PATH="$PATH" HOME="$TMP_ROOT/home" ORCA_HOME="$TMP_ROOT/home/.orca" node "$REPO_ROOT/dist/bin/orca.js" providers test local)'
